//! Tool types — re-exports plus class wrappers.
//!
//! The `JsToolCall` and `JsToolDefinition` plain-object mirrors are
//! auto-generated by `build.rs`. This module additionally exposes class
//! wrappers ([`JsToolCallClass`] and [`JsToolDefinitionClass`], JS names
//! `ToolCall` and `ToolDefinition`) with getters and constructors.

pub use blazen_llm::types::{ToolCall, ToolDefinition};

use napi_derive::napi;

// ---------------------------------------------------------------------------
// JsToolCallClass — class wrapper exposed to JS as `ToolCall`
// ---------------------------------------------------------------------------

/// Options for constructing a [`JsToolCallClass`] from JavaScript.
#[napi(object)]
pub struct ToolCallOptions {
    /// Provider-assigned identifier for this specific invocation.
    pub id: String,
    /// The name of the tool to invoke.
    pub name: String,
    /// The arguments to pass, as a JSON value.
    pub arguments: serde_json::Value,
}

/// Class wrapper around [`ToolCall`].
///
/// ```typescript
/// import { ToolCall } from 'blazen';
///
/// const tc = new ToolCall({ id: "call_1", name: "getWeather", arguments: { city: "NYC" } });
/// console.log(tc.name, tc.arguments);
/// ```
#[napi(js_name = "ToolCall")]
pub struct JsToolCallClass {
    pub(crate) inner: ToolCall,
}

#[napi]
#[allow(clippy::must_use_candidate, clippy::needless_pass_by_value)]
impl JsToolCallClass {
    /// Construct a tool call.
    #[napi(constructor)]
    pub fn new(options: ToolCallOptions) -> Self {
        Self {
            inner: ToolCall {
                id: options.id,
                name: options.name,
                arguments: options.arguments,
            },
        }
    }

    /// Provider-assigned invocation identifier.
    #[napi(getter)]
    pub fn id(&self) -> String {
        self.inner.id.clone()
    }

    /// The tool name.
    #[napi(getter)]
    pub fn name(&self) -> String {
        self.inner.name.clone()
    }

    /// The arguments to pass to the tool.
    #[napi(getter)]
    pub fn arguments(&self) -> serde_json::Value {
        self.inner.arguments.clone()
    }
}

impl From<ToolCall> for JsToolCallClass {
    fn from(inner: ToolCall) -> Self {
        Self { inner }
    }
}

impl From<&ToolCall> for JsToolCallClass {
    fn from(inner: &ToolCall) -> Self {
        Self {
            inner: inner.clone(),
        }
    }
}

// ---------------------------------------------------------------------------
// JsToolDefinitionClass — class wrapper exposed to JS as `ToolDefinition`
// ---------------------------------------------------------------------------

/// Options for constructing a [`JsToolDefinitionClass`] from JavaScript.
#[napi(object)]
pub struct ToolDefinitionOptions {
    /// The unique name of the tool.
    pub name: String,
    /// A human-readable description of what the tool does.
    pub description: String,
    /// A JSON Schema object describing the tool's input parameters.
    pub parameters: serde_json::Value,
}

/// Class wrapper around [`ToolDefinition`].
///
/// ```typescript
/// import { ToolDefinition } from 'blazen';
///
/// const td = new ToolDefinition({
///   name: "getWeather",
///   description: "Get current weather for a city",
///   parameters: { type: "object", properties: { city: { type: "string" } } },
/// });
/// ```
#[napi(js_name = "ToolDefinition")]
pub struct JsToolDefinitionClass {
    pub(crate) inner: ToolDefinition,
}

#[napi]
#[allow(clippy::must_use_candidate, clippy::needless_pass_by_value)]
impl JsToolDefinitionClass {
    /// Construct a tool definition.
    #[napi(constructor)]
    pub fn new(options: ToolDefinitionOptions) -> Self {
        Self {
            inner: ToolDefinition {
                name: options.name,
                description: options.description,
                parameters: options.parameters,
            },
        }
    }

    /// The tool name.
    #[napi(getter)]
    pub fn name(&self) -> String {
        self.inner.name.clone()
    }

    /// Human-readable description of the tool.
    #[napi(getter)]
    pub fn description(&self) -> String {
        self.inner.description.clone()
    }

    /// JSON Schema for the tool's input parameters.
    #[napi(getter)]
    pub fn parameters(&self) -> serde_json::Value {
        self.inner.parameters.clone()
    }
}

impl From<ToolDefinition> for JsToolDefinitionClass {
    fn from(inner: ToolDefinition) -> Self {
        Self { inner }
    }
}

impl From<&ToolDefinition> for JsToolDefinitionClass {
    fn from(inner: &ToolDefinition) -> Self {
        Self {
            inner: inner.clone(),
        }
    }
}
